import { DefaultReporter } from 'vitest/reporters'

export default class WatchReporter extends DefaultReporter {
  constructor(onTestRunEnd: typeof DefaultReporter.prototype.onTestRunEnd) {
    super();
    this.onTestRunEnd = onTestRunEnd;
    // onFinished in vitest@3
    // @ts-ignore
    this.onFinished = onTestRunEnd;
  }
}